            Status = "Delivered",
            Location = "San Francisco, CA",
            EstimatedDelivery = null,
            Updates =
            [
                new StatusUpdate
                {
                    Timestamp = new DateTimeOffset(2026, 5, 20, 10, 0, 0, TimeSpan.FromHours(-7)),
                    Description = "Package picked up",
                    Location = "Seattle, WA"
                },
                new StatusUpdate
                {
                    Timestamp = new DateTimeOffset(2026, 5, 22, 6, 45, 0, TimeSpan.FromHours(-7)),
                    Description = "Out for delivery",
                    Location = "San Francisco, CA"
                },
                new StatusUpdate
                {
                    Timestamp = new DateTimeOffset(2026, 5, 22, 14, 20, 0, TimeSpan.FromHours(-7)),
                    Description = "Delivered — signed by J. Smith",
                    Location = "San Francisco, CA"
                }
            ]
        },
        ["TRK-3003"] = new Shipment
        {
            TrackingNumber = "TRK-3003",
            Status = "Pending",
            Location = "Dallas, TX",
            EstimatedDelivery = new DateTimeOffset(2026, 6, 5, 12, 0, 0, TimeSpan.FromHours(-5)),
            Updates =
            [
                new StatusUpdate
                {
                    Timestamp = new DateTimeOffset(2026, 5, 27, 16, 0, 0, TimeSpan.FromHours(-5)),
                    Description = "Label created, awaiting pickup",
                    Location = "Dallas, TX"
                }
            ]
        }
    };

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
